def gen_protocol(output_type):
    PROTOCOLS = {
     "research": {
      "evidence":"open the cited documents",
      "key_check":"verify each citation exists and supports the claim",
      "artifact":"source map: file -> claim mapping"},
     "code":{"evidence":"run tests, inspect diff",
      "key_check":"diff shows only intended changes",
      "artifact":"test run output + diff"},
    }
    p = PROTOCOLS.get(output_type, PROTOCOLS["research"])
    print(f"Output type: {output_type}")
    for k, v in p.items():
        print(f"  {k}: {v}")
gen_protocol("research")
